// ============================================
// BUILD REQUEST - Assembles the OpenAI API call
// ============================================

// Get trigger data
const trigger = $('Telegram Trigger').first().json;
const chatId = String(trigger.message.chat.id);
const messageText = trigger.message.text || '';
const firstName = trigger.message.from.first_name || 'there';
const username = trigger.message.from.username || '';

// Find existing lead in Leads sheet
const allLeads = $('Read Leads').all().map(i => i.json);
const existingLead = allLeads.find(l => String(l.chat_id) === chatId);
const isNewLead = !existingLead || !existingLead.chat_id;

// Get conversation history for this chat_id
const allConvos = $('Read Conversations').all().map(i => i.json);
const myHistory = allConvos
  .filter(c => String(c.chat_id) === chatId)
  .sort((a, b) => new Date(a.timestamp) - new Date(b.timestamp))
  .slice(-20);

// ---- SYSTEM PROMPT ----
const systemPrompt = `You are Aisha, a real estate consultant at Dubai Premier Properties. You chat with clients on Telegram who are interested in buying or renting property in Dubai. You have 8 years of experience in the Dubai market.

HOW YOU TALK:
- Keep it casual and warm, like texting a friend who happens to know everything about Dubai real estate
- Short messages. 2-4 sentences max. Nobody reads novels on Telegram
- Use line breaks between thoughts
- Never use bullet points or numbered lists in chat
- Occasionally use simple expressions like absolutely, great choice, love that area
- Never say I am an AI or as an AI or anything like that
- Never use the word assist - say help instead
- Do not be overly enthusiastic or salesy. Be real.
- Mirror the client language style

YOUR GOAL (in order):
1. Build rapport - make them feel heard
2. Understand what they want (budget, area, type, timeline, purpose)
3. Answer questions honestly and knowledgeably
4. If they seem ready, suggest a viewing or connect with a senior consultant
5. If not ready, keep the door open warmly

QUALIFYING QUESTIONS (ask naturally, not like a form):
- What kind of property are you looking at?
- Any areas you are drawn to?
- What is your budget range?
- Is this for living in or as an investment?
- When are you looking to make a move?

MARKET KNOWLEDGE:
- Dubai Marina: Studios from AED 800K, 1BR from AED 1.2M, 2BR from AED 2M+
- Downtown Dubai / Burj Khalifa area: 1BR from AED 1.5M, 2BR from AED 2.5M+
- JBR: 1BR from AED 1.3M, 2BR from AED 2.2M+
- Palm Jumeirah: 1BR from AED 1.8M, 2BR from AED 3M+, Villas from AED 15M+
- Business Bay: Studios from AED 700K, 1BR from AED 1M, 2BR from AED 1.8M+
- JVC: Studios from AED 450K, 1BR from AED 700K (affordable option)
- Dubai Hills Estate: 3BR villas from AED 3.5M, apartments from AED 1M
- Creek Harbour: 1BR from AED 1.2M, 2BR from AED 2M+
- Rental yields: 5-8% average, higher in affordable areas
- Off-plan: 10-20% cheaper, payment plans available (60/40 or 80/20)
- Transaction costs: ~8% total (4% DLD fee, 2% agency, ~2% other)
- No property tax. No income tax. Major draw for investors.
- Golden visa for property purchases above AED 2M

WHEN TO SUGGEST BOOKING:
If client has shared budget + area + timeline within 3 months, suggest: I could set up a couple of viewings for you this week if you are free? No pressure at all.

WHEN TO HAND OFF:
If client asks for specific unit availability, contract details, payment plans, or legal questions - say: Let me connect you with our senior consultant directly for that - they handle all the details and can give you exact figures.

WHAT NOT TO DO:
- Do not make up specific unit numbers or availability
- Do not promise specific returns
- Do not push. If someone says they are just looking, respect that
- Do not ask multiple questions in one message

OUTPUT FORMAT:
You must respond in valid JSON with exactly two fields:
1. reply - your message to send to the client
2. lead_data - an object with any NEW information learned from THIS message only

For lead_data fields, set to null if no new info was learned. Fields:
- status: new | cold | warm | hot | booked | handed_off
- budget_min: number in AED or null
- budget_max: number in AED or null
- location_preference: string or null
- property_type: apartment | villa | townhouse | penthouse | studio or null
- bedrooms: string like 2 or 2-3 or null
- purpose: investment | own_use | rental | undecided or null
- timeline: immediate | 1-3 months | 3-6 months | exploring or null
- nationality: string or null
- phone: string or null
- email: string or null
- notes: brief important note or null
- wants_booking: true/false/null
- wants_handoff: true/false/null

STATUS LOGIC:
- new: First message, no info yet
- cold: Just browsing, no timeline, vague interest
- warm: Has shared some preferences (budget OR area OR timeline)
- hot: Has budget + area + timeline within 3 months
- booked: Viewing scheduled
- handed_off: Connected to human agent`;

// Build messages array
const messages = [{ role: 'system', content: systemPrompt }];

// Add lead context if returning user
if (existingLead && existingLead.status) {
  const ctx = ['Current lead profile:'];
  if (existingLead.status) ctx.push('- Status: ' + existingLead.status);
  if (existingLead.budget_min) ctx.push('- Budget min: AED ' + existingLead.budget_min);
  if (existingLead.budget_max) ctx.push('- Budget max: AED ' + existingLead.budget_max);
  if (existingLead.location_preference) ctx.push('- Area: ' + existingLead.location_preference);
  if (existingLead.property_type) ctx.push('- Property type: ' + existingLead.property_type);
  if (existingLead.bedrooms) ctx.push('- Bedrooms: ' + existingLead.bedrooms);
  if (existingLead.purpose) ctx.push('- Purpose: ' + existingLead.purpose);
  if (existingLead.timeline) ctx.push('- Timeline: ' + existingLead.timeline);
  if (existingLead.notes) ctx.push('- Notes: ' + existingLead.notes);
  if (existingLead.message_count) ctx.push('- Messages exchanged: ' + existingLead.message_count);
  messages.push({ role: 'system', content: ctx.join('\n') });
}

// Add conversation history
for (const conv of myHistory) {
  const role = conv.direction === 'inbound' ? 'user' : 'assistant';
  // For assistant messages, extract just the reply text if it was stored as JSON
  let content = conv.message;
  if (role === 'assistant') {
    try {
      const parsed = JSON.parse(content);
      if (parsed.reply) content = parsed.reply;
    } catch(e) { /* not JSON, use as-is */ }
  }
  messages.push({ role, content });
}

// Add current message
messages.push({ role: 'user', content: messageText });

// Build the full OpenAI request body
const requestBody = {
  model: 'gpt-4o-mini',
  messages: messages,
  response_format: {
    type: 'json_schema',
    json_schema: {
      name: 'agent_response',
      strict: true,
      schema: {
        type: 'object',
        required: ['reply', 'lead_data'],
        additionalProperties: false,
        properties: {
          reply: { type: 'string' },
          lead_data: {
            type: 'object',
            additionalProperties: false,
            required: ['status', 'budget_min', 'budget_max', 'location_preference', 'property_type', 'bedrooms', 'purpose', 'timeline', 'nationality', 'phone', 'email', 'notes', 'wants_booking', 'wants_handoff'],
            properties: {
              status: { type: ['string', 'null'] },
              budget_min: { type: ['number', 'null'] },
              budget_max: { type: ['number', 'null'] },
              location_preference: { type: ['string', 'null'] },
              property_type: { type: ['string', 'null'] },
              bedrooms: { type: ['string', 'null'] },
              purpose: { type: ['string', 'null'] },
              timeline: { type: ['string', 'null'] },
              nationality: { type: ['string', 'null'] },
              phone: { type: ['string', 'null'] },
              email: { type: ['string', 'null'] },
              notes: { type: ['string', 'null'] },
              wants_booking: { type: ['boolean', 'null'] },
              wants_handoff: { type: ['boolean', 'null'] }
            }
          }
        }
      }
    }
  },
  temperature: 0.7,
  max_tokens: 500
};

return [{
  json: {
    chatId,
    firstName,
    username,
    messageText,
    isNewLead,
    existingLead: existingLead || {},
    requestBody,
    timestamp: new Date().toISOString()
  }
}];

// ================================================
// PROCESS RESPONSE - Parse AI output + prepare data
// ================================================

const openaiResponse = $input.first().json;
const buildData = $('Build Request').first().json;

// Parse the AI response
let aiContent;
try {
  aiContent = JSON.parse(openaiResponse.choices[0].message.content);
} catch(e) {
  // Fallback if JSON parsing fails
  aiContent = {
    reply: openaiResponse.choices[0].message.content || 'Sorry, I had a moment there. Could you say that again?',
    lead_data: { status: null }
  };
}

const reply = aiContent.reply;
const newData = aiContent.lead_data || {};

// Filter out null values from new lead data
const cleanNewData = {};
for (const [key, value] of Object.entries(newData)) {
  if (value !== null && value !== undefined) {
    cleanNewData[key] = value;
  }
}

// Merge with existing lead data
const existing = buildData.existingLead || {};
const merged = { ...existing };

// Only overwrite with genuinely new values
for (const [key, value] of Object.entries(cleanNewData)) {
  merged[key] = value;
}

// Set metadata
merged.chat_id = buildData.chatId;
merged.first_name = merged.first_name || buildData.firstName;
merged.username = merged.username || buildData.username;
merged.last_contact = buildData.timestamp;
merged.message_count = (parseInt(merged.message_count) || 0) + 1;

if (buildData.isNewLead) {
  merged.first_contact = buildData.timestamp;
  merged.follow_up_count = 0;
  if (!merged.status) merged.status = 'new';
}

// Should we notify the owner?
const notifyOwner = (
  merged.status === 'hot' ||
  cleanNewData.wants_booking === true ||
  cleanNewData.wants_handoff === true
);

// Build owner notification message
let ownerMessage = '';
if (notifyOwner) {
  ownerMessage = '🔥 HOT LEAD ALERT!\n\n';
  ownerMessage += 'Name: ' + (merged.first_name || 'Unknown') + '\n';
  ownerMessage += 'Telegram: @' + (merged.username || 'N/A') + '\n';
  ownerMessage += 'Status: ' + (merged.status || 'unknown') + '\n';
  if (merged.budget_min || merged.budget_max) {
    ownerMessage += 'Budget: AED ' + (merged.budget_min || '?') + ' - ' + (merged.budget_max || '?') + '\n';
  }
  if (merged.location_preference) ownerMessage += 'Area: ' + merged.location_preference + '\n';
  if (merged.property_type) ownerMessage += 'Type: ' + merged.property_type + '\n';
  if (merged.timeline) ownerMessage += 'Timeline: ' + merged.timeline + '\n';
  if (merged.purpose) ownerMessage += 'Purpose: ' + merged.purpose + '\n';
  ownerMessage += '\nLatest message: ' + buildData.messageText;
  if (cleanNewData.wants_booking) ownerMessage += '\n\n⚡ WANTS TO BOOK A VIEWING';
  if (cleanNewData.wants_handoff) ownerMessage += '\n\n📞 WANTS TO SPEAK TO SOMEONE';
}

return [{
  json: {
    reply,
    chatId: buildData.chatId,
    firstName: buildData.firstName,
    username: buildData.username,
    messageText: buildData.messageText,
    isNewLead: buildData.isNewLead,
    notifyOwner,
    ownerMessage,
    timestamp: buildData.timestamp,
    leadData: merged,
    newExtracted: cleanNewData
  }
}];
